SELECT c.id, c.team_id, c.task_id, t.task_name, c.user_id, c.checkin_date, c.complete_value, t.target_unit, c.content, c.images, c.feeling, c.is_supplement, c.like_count, c.comment_count, c.duration, c.create_time FROM study_team_checkin c LEFT JOIN study_team_task t ON c.task_id = t.id WHERE c.team_id = #{teamId} AND c.is_deleted = 0
AND c.task_id = #{taskId}
ORDER BY c.create_time DESC LIMIT #{limit} OFFSET #{offset}

SELECT c.id, c.team_id, c.task_id, t.task_name, c.user_id, c.checkin_date, c.complete_value, t.target_unit, c.content, c.images, c.feeling, c.is_supplement, c.like_count, c.comment_count, c.duration, c.create_time FROM study_team_checkin c LEFT JOIN study_team_task t ON c.task_id = t.id WHERE c.user_id = #{userId} AND c.is_deleted = 0
AND c.team_id = #{teamId}
AND c.checkin_date >= #{startDate}
AND c.checkin_date <= #{endDate}
ORDER BY c.checkin_date DESC, c.create_time DESC

WITH RECURSIVE streak AS (
    SELECT checkin_date, 1 as day_count
    FROM study_team_checkin
    WHERE user_id = #{userId}
    AND team_id = #{teamId}

        AND task_id = #{taskId}

    AND checkin_date = #{today}
    AND is_deleted = 0

    UNION ALL

    SELECT c.checkin_date, s.day_count + 1
    FROM study_team_checkin c
    JOIN streak s ON c.checkin_date = DATE_SUB(s.checkin_date, INTERVAL 1 DAY)
    WHERE c.user_id = #{userId}
    AND c.team_id = #{teamId}

        AND c.task_id = #{taskId}

    AND c.is_deleted = 0
)
SELECT COALESCE(MAX(day_count), 0) FROM streak

SELECT COALESCE(MAX(streak_len), 0)
FROM (
    SELECT COUNT(1) AS streak_len
    FROM (
        SELECT DISTINCT checkin_date,
               DATE_SUB(checkin_date, INTERVAL ROW_NUMBER() OVER (ORDER BY checkin_date) DAY) AS grp
        FROM study_team_checkin
        WHERE user_id = #{userId}
        AND team_id = #{teamId}

            AND task_id = #{taskId}

        AND is_deleted = 0
    ) streak_groups
    GROUP BY grp
) streak_summary

SELECT COUNT(DISTINCT checkin_date)
FROM study_team_checkin
WHERE user_id = #{userId}
AND team_id = #{teamId}
AND is_deleted = 0

SELECT DISTINCT user_id
FROM study_team_checkin
WHERE team_id = #{teamId}

    AND task_id = #{taskId}

AND checkin_date = #{date}
AND is_deleted = 0

SELECT user_id, COUNT(1) AS value
FROM study_team_checkin
WHERE team_id = #{teamId}
AND is_deleted = 0

    AND checkin_date >= #{startDate}


    AND checkin_date <= #{endDate}


    AND user_id IN

        #{userId}


GROUP BY user_id

SELECT user_id, COALESCE(SUM(duration), 0) AS value
FROM study_team_checkin
WHERE team_id = #{teamId}
AND is_deleted = 0

    AND checkin_date >= #{startDate}


    AND checkin_date <= #{endDate}


    AND user_id IN

        #{userId}


GROUP BY user_id

SELECT checkin_date AS statDate, COALESCE(SUM(duration), 0) AS value
FROM study_team_checkin
WHERE team_id = #{teamId}
AND is_deleted = 0

    AND checkin_date >= #{startDate}


    AND checkin_date <= #{endDate}

GROUP BY checkin_date
ORDER BY checkin_date ASC

SELECT team_id, COUNT(DISTINCT CONCAT(checkin_date, ':', user_id)) AS value FROM study_team_checkin WHERE is_deleted = 0 AND checkin_date BETWEEN #{startDate} AND #{endDate}
AND team_id IN
#{teamId}
GROUP BY team_id

SELECT COUNT(1)
FROM study_team_checkin_like
WHERE checkin_id = #{checkinId}
AND user_id = #{userId}

